using TMPro;
using UnityEngine;
using UnityEngine.InputSystem;
using UnityEngine.UI;

/// <summary>
/// Uma linha de "Mudar controles" (Menu de Pausa: Opções, Tarefa #12): mostra o
/// nome da acção e a tecla/botão actualmente associado, com um botão "Mudar"
/// que entra em modo de escuta (<see cref="InputActionRebindingExtensions.PerformInteractiveRebinding"/>)
/// e regista o próximo input do jogador como novo binding.
///
/// "bindingIndex" identifica qual binding desta acção esta linha controla —
/// 0 para acções simples; para composites 2D (Move/Look: Up/Down/Left/Right)
/// usa o índice do binding composite (1=Up, 2=Down, 3=Left, 4=Right, pela ordem
/// típica do Input System).
///
/// Não persiste nada por si só — <see cref="ControlsRebindSectionUI"/> grava
/// todos os overrides do asset de uma vez, depois de qualquer linha terminar um rebind.
/// </summary>
public class RebindRowUI : MonoBehaviour
{
    [SerializeField] private InputActionReference action;

    [Tooltip("Índice do binding dentro da acção. 0 para acções simples; para composites 2D, o índice da parte (Up/Down/Left/Right).")]
    [SerializeField] private int bindingIndex;

    [SerializeField] private TMP_Text actionNameText;
    [SerializeField] private TMP_Text bindingDisplayText;
    [SerializeField] private Button rebindButton;

    [Tooltip("Mostrado enquanto o botão está à espera do próximo input do jogador.")]
    [SerializeField] private GameObject waitingIndicator;

    [SerializeField] private string waitingText = "Prima uma tecla/botão...";
    [SerializeField] private string displayNameOverride;

    private InputActionRebindingExtensions.RebindingOperation rebindOperation;

    /// <summary>Disparado quando um rebind termina com sucesso — ControlsRebindSectionUI usa isto para gravar os overrides.</summary>
    public System.Action<RebindRowUI> RebindCompleted;

    private void Awake()
    {
        if (rebindButton != null) rebindButton.onClick.AddListener(StartRebind);
        RefreshDisplay();
    }

    private void OnDisable()
    {
        rebindOperation?.Cancel();
    }

    public void RefreshDisplay()
    {
        if (action == null || action.action == null) return;

        if (actionNameText != null)
            actionNameText.text = !string.IsNullOrEmpty(displayNameOverride) ? displayNameOverride : action.action.name;

        if (bindingDisplayText != null)
            bindingDisplayText.text = action.action.GetBindingDisplayString(bindingIndex);

        if (waitingIndicator != null) waitingIndicator.SetActive(false);
    }

    public void StartRebind()
    {
        if (action == null || action.action == null) return;

        var inputAction = action.action;

        if (waitingIndicator != null) waitingIndicator.SetActive(true);
        if (bindingDisplayText != null) bindingDisplayText.text = waitingText;
        if (rebindButton != null) rebindButton.interactable = false;

        inputAction.Disable();

        rebindOperation = inputAction.PerformInteractiveRebinding(bindingIndex)
            .WithControlsExcluding("Mouse")
            .WithCancelingThrough("<Keyboard>/escape")
            .OnMatchWaitForAnother(0.1f)
            .OnComplete(_ => FinishRebind(inputAction))
            .OnCancel(_ => FinishRebind(inputAction))
            .Start();
    }

    private void FinishRebind(InputAction inputAction)
    {
        rebindOperation?.Dispose();
        rebindOperation = null;

        inputAction.Enable();

        if (rebindButton != null) rebindButton.interactable = true;

        RefreshDisplay();
        RebindCompleted?.Invoke(this);
    }

    /// <summary>Remove o override desta linha, voltando ao binding original.</summary>
    public void ResetToDefault()
    {
        if (action == null || action.action == null) return;

        action.action.RemoveBindingOverride(bindingIndex);
        RefreshDisplay();
    }
}
